import pytest
import requests

@pytest.mark.parametrize("cred_fixture,patient_fixture,exp_status,exp_audit", [
    ("assigned_clinician_credentials", "assigned_patient_id", 200, "0"),
    ("unassigned_clinician_credentials", "assigned_patient_id", 403, "8"),
])
def test_decision_table_assigned_and_unassigned_clinicians_audit_outcomes(
    request, fhir_base_url, cred_fixture, patient_fixture, exp_status, exp_audit, audit_poller
):
    creds = request.getfixturevalue(cred_fixture)
    patient_id = request.getfixturevalue(patient_fixture)
    token = <get_auth_token>(creds)
    headers = {"Authorization": f"Bearer {token}", "Accept": "application/fhir+json"}

    resp = requests.get(f"{fhir_base_url}/Patient/{patient_id}", headers=headers)

    assert resp.status_code == exp_status

    audit = audit_poller(
        criteria={"entity": patient_id, "agent": creds["user_id"], "outcome": exp_audit}
    )
    assert audit is not None, f"AuditEvent outcome={exp_audit} not found for {creds['user_id']}"
    assert audit["outcome"] == exp_audit
